void ProcessDialogEvent(){	ref NPChar;	aref Link, NextDiag;	DeleteAttribute(&Dialog, "Links");	makeref(NPChar, CharacterRef);	makearef(Link, Dialog.Links);	makearef(NextDiag, NPChar.Dialog);	switch (Dialog.CurrentNode)	{		case "first time":			dialog.text = StringFromKey("Esteban_1");			link.l1 = StringFromKey("Esteban_2");			link.l1.go = "1";		break;		case "1":			dialog.text = StringFromKey("Esteban_3");			link.l1 = StringFromKey("Esteban_4");			link.l1.go = "exit";			AddDialogExitQuest("FL8_s24");			NextDiag.TempNode = "2";		break;		case "2":			dialog.text = StringFromKey("Esteban_5");			link.l1 = StringFromKey("Esteban_6");			link.l1.go = "3";		break;		case "3":			dialog.text = StringFromKey("Esteban_7");			link.l1 = StringFromKey("Esteban_8");			link.l1.go = "4";		break;		case "4":			dialog.text = "...";			link.l1 = StringFromKey("Esteban_9");			link.l1.go = "5";		break;		case "5":			TakeItemFromCharacter(pchar, "FQ_letter7");			dialog.text = StringFromKey("Esteban_10");			link.l1 = StringFromKey("Esteban_11");			link.l1.go = "6";		break;		case "6":			dialog.text = StringFromKey("Esteban_12");			link.l1 = StringFromKey("Esteban_13");			link.l1.go = "7";		break;		case "7":			dialog.text = StringFromKey("Esteban_14");			link.l1 = StringFromKey("Esteban_15");			link.l1.go = "8";		break;		case "8":			dialog.text = StringFromKey("Esteban_16");			if (sti(pchar.money) >= 1000)			{				link.l1 = StringFromKey("Esteban_17");				link.l1.go = "9";			}			link.l2 = StringFromKey("Esteban_18");			link.l2.go = "9a";		break;		case "9":			OfficersReaction("good");			AddMoneyToCharacter(pchar, -1000);			ChangeCharacterReputation(pchar, 10);			dialog.text = StringFromKey("Esteban_19");			link.l1 = "...";			link.l1.go = "exit";		break;		case "9a":			OfficersReaction("bad");			ChangeCharacterReputation(pchar, -10);			dialog.text = StringFromKey("Esteban_20");			link.l1 = "...";			link.l1.go = "exit";		break;		case "exit":			if (CheckAttribute(NextDiag, "TempNode")) NextDiag.CurrentNode = NextDiag.TempNode;			DialogExit();		break;	}}